void Detail_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
       //-- new logic for BrdStd Percentage using total EggsSetted
// --- Get Values ---
decimal eggsSettedSTD = GetCurrentColumnValue("EggsSetted") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("EggsSetted"))
    : 0;

decimal stadHatchability = GetCurrentColumnValue("StadHatchability") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("StadHatchability"))
    : 0;

// --- Calculate @BrdStdAsNumber ---
eggsSettedSumStdbrds += eggsSettedSTD ;
brdStdAsNumberTotal += (stadHatchability * eggsSettedSTD / 100);

//new logic for Dev 
   // --- Calculate @TotalChicks ---
decimal selChicks = GetCurrentColumnValue("SelChicks") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("SelChicks"))
    : 0;

decimal culls = GetCurrentColumnValue("Culls") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("Culls"))
    : 0;

decimal deadChicks = GetCurrentColumnValue("DeadChicks") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("DeadChicks"))
    : 0;

decimal totalChicks = selChicks + culls + deadChicks;

// --- Calculate @TotalHatchPrec ---
decimal eggsSettedDev = GetCurrentColumnValue("EggsSetted") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("EggsSetted"))
    : 0;

if (eggsSettedDev > 0)
{
    totalHatchPrec = (totalChicks / eggsSettedDev ) * 100;;
}

// --- Get StadHatchability ---
stadHatchabilityDev = GetCurrentColumnValue("StadHatchability") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("StadHatchability"))
    : 0;

//Logic To get Dev for all records 
    // --- Cumulative variables (declare at class level) ---
decimal eggsSettedSumDev = 0;
decimal totalChicksSumDev = 0;

// --- In your script ---
// --- Get current row values ---
decimal eggsSettedHatDev = GetCurrentColumnValue("EggsSetted") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("EggsSetted"))
    : 0;

decimal selChicksDev = GetCurrentColumnValue("SelChicks") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("SelChicks"))
    : 0;

decimal cullsDev = GetCurrentColumnValue("Culls") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("Culls"))
    : 0;

decimal deadChicksDev = GetCurrentColumnValue("DeadChicks") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("DeadChicks"))
    : 0;

decimal stadHatchabilityHatDev = GetCurrentColumnValue("StadHatchability") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("StadHatchability"))
    : 0;

// --- Calculate current row values ---
decimal currentTotalChicks = selChicksDev + cullsDev + deadChicksDev ;
decimal currentBrdStdAsNumber = stadHatchabilityHatDev * eggsSettedHatDev / 100;

// --- Accumulate sums ---
eggsSettedSumDev += eggsSettedHatDev ;
totalChicksSumDev += currentTotalChicks;
brdStdAsNumberTotalDev += currentBrdStdAsNumber;

// --- Calculate @GT_TotalChicksPer ---
// --- Calculate @GT_TotalChicksPer ---
if (eggsSettedSumDev > 0)
{
    gtTotalChicksPer = (totalChicksSumDev / eggsSettedSumDev) * 100;
}

// --- Calculate @GT_BrdStdAsNumber as percentage ---
if (eggsSettedSumDev > 0)
{
    gtBrdStdAsNumberPercent = (brdStdAsNumberTotalDev / eggsSettedSumDev) * 100;

}

//Cum STDBrd Logic 
   // --- Declare cumulative variables at class level ---

// --- In Before Print script ---
// --- Get current row values ---
decimal cumSettingEggsSTDbrd = GetCurrentColumnValue("CumSettingEggs") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("CumSettingEggs"))
    : 0;

decimal stadCumHatchabilitySTDbrd = GetCurrentColumnValue("StadCumHatchability") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("StadCumHatchability"))
    : 0;

decimal stadCumHatchabilitySTDbrdGrade = GetCurrentColumnValue("StadCumHatchabilityAGrade") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("StadCumHatchabilityAGrade"))
    : 0;

// --- Calculate current row @BrdStdAsNumber_Cum ---
// --- Calculate current row @BrdStdAsNumber_Cum ---

// --- Accumulate sums ---
cumSettedSumSTDBrd  += cumSettingEggsSTDbrd ;
brdStdAsNumberCumTotalSTDBrd += (stadCumHatchabilitySTDbrd * cumSettingEggsSTDbrd / 100);
brdStdAsNumberCumTotalSTDBrdGrade += (stadCumHatchabilitySTDbrdGrade * cumSettingEggsSTDbrd / 100);

// --- Assign to Cell ---
    if (cumSettedSumSTDBrd > 0)
    {
        ResultSTDBrd =  (brdStdAsNumberCumTotalSTDBrd * 100) / cumSettedSumSTDBrd;
    }
// Assign to another cell for Grade 
if (cumSettedSumSTDBrd > 0)
    {
        ResultSTDBrdGrade =  (brdStdAsNumberCumTotalSTDBrdGrade * 100) / cumSettedSumSTDBrd;
    }

//Logic for Cum Dev
// --- Get Values ---
decimal eggsSettedSTDCum = GetCurrentColumnValue("CumSettingEggs") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("CumSettingEggs"))
    : 0;

decimal stadHatchabilityCum = GetCurrentColumnValue("StadCumHatchability") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("StadCumHatchability"))
    : 0;
decimal AGradestadHatchabilityCum = GetCurrentColumnValue("StadCumHatchabilityAGrade") != null
    ? Convert.ToDecimal(GetCurrentColumnValue("StadCumHatchabilityAGrade"))
    : 0;

// --- Calculate @BrdStdAsNumber ---
eggsSettedSumStdbrdsCum += eggsSettedSTDCum ;
brdStdAsNumberTotalCum += (stadHatchabilityCum * eggsSettedSTDCum / 100);
AGradebrdStdAsNumberTotalCum  += (AGradestadHatchabilityCum * eggsSettedSTDCum / 100);
    // --- Get values from the current row ---
    decimal eggsSettedCum = GetCurrentColumnValue("CumSettingEggs") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("CumSettingEggs"))
        : 0;

    decimal BroilerChicksCum = GetCurrentColumnValue("CumBroiler") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("CumBroiler"))
        : 0;

    decimal BroilerChicksCumAGrade = GetCurrentColumnValue("CumBroiler") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("CumBroiler"))
        : 0;


    decimal cullsCum = GetCurrentColumnValue("CumCulls") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("CumCulls"))
        : 0;

    decimal deadChicksCum = GetCurrentColumnValue("CumDeadChicks") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("CumDeadChicks"))
        : 0;

    // --- TotalChicks = BroilerChicks + Culls + DeadChicks ---
    decimal totalChicksCum = BroilerChicksCum + cullsCum + deadChicksCum ;
    totalChicksSumCum += totalChicksCum ;
    decimal totalChicksCumAGrade = BroilerChicksCumAGrade  ;
    totalChicksSumCumAGrade += totalChicksCumAGrade ;
    // --- Calculate percentages ---
    TotalHatchCum  = (eggsSettedSumStdbrdsCum > 0)
        ? (totalChicksSumCum * 100 / eggsSettedSumStdbrdsCum )
        : 0;
    // --- Calculate Result ---
    if(eggsSettedSumStdbrdsCum > 0){

              BrdSTDTotalCum =  (brdStdAsNumberTotalCum * 100 / eggsSettedSumStdbrdsCum);

      }

   //Calculate Percetnages for Grade
   TotalHatchCumGrade  = (eggsSettedSumStdbrdsCum > 0)
        ? (totalChicksSumCumAGrade * 100 / eggsSettedSumStdbrdsCum )
        : 0;
    // --- Calculate Result ---
    if(eggsSettedSumStdbrdsCum > 0){

              BrdSTDTotalCumAGrade =  (AGradebrdStdAsNumberTotalCum  * 100 / eggsSettedSumStdbrdsCum);

      }

}

private void xrTableCell26_BeforePrint(object sender, System.ComponentModel.CancelEventArgs e) {
     // --- Get Values ---
    decimal eggsSetted = GetCurrentColumnValue("EggsSetted") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("EggsSetted"))
        : 0;
    decimal selChicks = GetCurrentColumnValue("SelChicks") != null
        ? Convert.ToDecimal(GetCurrentColumnValue("SelChicks"))
        : 0;
    // --- Calculate Result ---
    decimal result = (eggsSetted > 0)
        ? (selChicks * 100 / eggsSetted)
        : 0;

    // --- Assign to Cell ---
    ((XRTableCell)sender).Text = result.ToString("0.00");
     eggsSettedSum += eggsSetted;
     selChicksSum += selChicks ;

}

